sparql_query:
PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?county ?sviRecord ?sviYear ?housingTransportationScore ?hailEvent ?hailType ?hailStart ?hailEnd ?flashFloodEvent ?flashFloodType ?flashFloodStart ?flashFloodEnd
WHERE {
  ?county a goo:County .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear ?sviYear ;
             goo:sviHousingTransportationTheme ?housingTransportationScore .
  FILTER (?sviYear = 2020)
  FILTER (?housingTransportationScore >= 0.85)

  ?hailEvent a goo:StormEventRecord ;
             goo:occurredInCounty ?county ;
             goo:stormEventType ?hailType ;
             goo:eventStartTime ?hailStart ;
             goo:eventEndTime ?hailEnd .
  FILTER (REGEX(STR(?hailType), "Hail", "i"))

  ?flashFloodEvent a goo:StormEventRecord ;
                   goo:occurredInCounty ?county ;
                   goo:stormEventType ?flashFloodType ;
                   goo:eventStartTime ?flashFloodStart ;
                   goo:eventEndTime ?flashFloodEnd .
  FILTER (REGEX(STR(?flashFloodType), "Flash Flood", "i"))

  FILTER (?hailStart <= ?flashFloodStart)
  FILTER ((?flashFloodStart - ?hailStart) <= "PT12H"^^xsd:dayTimeDuration)
}
ORDER BY DESC(?housingTransportationScore) ?county ?hailStart ?flashFloodStart
LIMIT 10
